INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1614, 197599, 10, 11, '[转贴]转个顾湘的贴，我就是很喜欢', '不足一个月的寒假之后回到莫斯科，仍白雪皑皑，夜空湛蓝冷艳，换心底一声叹息，当下无话。第二天便搭乘火车去往摩尔曼斯克。从天气预报看当地气温竟也不过零下五度左右，已经知道极光是看不到的了，除非气温一夜陡降十几二十度，可能性微乎其微。这趟旅行但出于某种需要，类似高烧睡梦中的一句呻吟，或在泳池中的想法：“游到那头再游回来”，其实停着不动未尝不可。
<br>同一包厢的乘客有一位上年纪的妇人和一个俊秀朴素的年轻人，我猜他们是母子，但一直没能确定，也许是他们始终亲密而积极地交谈，我想当然地认为散淡和无所谓些似乎更合乎常理；也许是谈话的内容（我甚至听到那个男孩说到“德国哲学”），当然，我并不了解其他所有的亲子之间是种什么样的关系，我读过一本很好看的书叫《我的俄国母亲》，然而不是每个人都生活在敏感、紧张和复杂的刺痛里。有阵子我不断从上铺往下掉东西，男孩不厌其烦地拾给我，拾多了就笑了，我也很不好意思，最后他拾到一张我回上海坐的俄航飞机从杂志上撕下来带漂亮图片的一页，那时我实在太困了，飞机晚起飞八小时，看不到两行就眼皮就变得很沉重。男孩笑着念标题：“注意：北极熊。”它们孤独、骄傲、好奇又强悍，非常动人。
<br>
<br>约两星期前我去南方看望我的母亲。我的记忆力使她欣慰――例如，我指出上回一起买电视经过的路口，一条岔路在夏天总是堆满树上掉下来的杨桃，骑自行车打那儿走，纵然小心，仍免不了从汁液饱满的果实上碾过，诸如此类，我只消随便挑拣出很少令她相信我不曾也没有打算去遗弃那些时光――然而有时也让她切齿痛恨。有一次我想是她无法接受让她感到陌生和诧异的我的套近乎的方式，在街上，我只好搂着她，她在我怀里嘤嘤哭泣，惹人心烦，还有她絮絮不休的对往事的追述和解释，最后我忍无可忍喝止了她，她很震惊。我也不无懊恼。后来，她又郑重而兴冲冲地带我上银行取出她的积蓄，攀着我的肩膀在耳边喃喃说些孩子气的傻话，惹人心烦意乱。我不禁想父亲也曾这样，接过她的钱，对这个长了一颗简单善良又执拗地一厢情愿的头脑的女人疼惜而不能，结果这种愿望变成速速离她而去的愿望，对渺茫的下一次相遇仍感惶惑。
<br>夜里和少年时结识的男孩喝酒，一个说着他的计划，去广州另觅工作及年内结婚，另一个闷闷不乐地笑着，我问他摩托车呢，他回答说卖掉了。呼啸的年月也过去了。而这小城即便冬夜也吹拂着温润如水的风，我只套一件单薄破烂夹克，漫无目的走在街上，依然还是个小混混。造起来许多簇新高楼，像照相馆里的背景纸挂在城的壳子边上。
<br>
<br>之前去北京见到好友D，仍住在他那里，屋里跟从前一样。D还是那么好，家人也好。初相识时欢喜不禁赞作鲜衣怒马的人，如今变得大人模样。我呢？“你看着有点累，”他说，“要不给你拿件随便穿着睡觉的衣服？”有个晚上我们一直玩一个PS2上的高尔夫，世界上最百无聊赖的游戏，两人对电视坐着，一会儿换着场地季节，风景好，有股养老院的气氛。
<br>一旦所有灯都安息，这个赶时髦的家伙到处扔着的许多只手表嚓嚓嚓的声响便从四面八方传来，使我登时回顾起逝去的时光。在时光逝去时，我给予了极大的耐心，出于对晚点飞机所怀的希望（是否只是幻觉？）。随后我想起了从空中见到的被冰雪覆盖的雄伟山脉，像一颗素昧平生、寒冷寂寥的星球；莫斯科城如一张缀满珠宝钻石硕大无朋的蜘蛛网在黑暗的凌晨铺展开来，片刻后浮至云端。很快便要由眼下这一狭小空间进入到又一个明天，这过程总是惊心动魄。仿佛飞入饱含零度以下却仍呈液态的水滴的云中，翅膀打破阻碍水滴成冰的薄膜，它们立刻围绕冲破它们的东西凝固成玻璃状，就像甲壳纲的鱼类附着在鲸身上一样，骤然急速下坠。你也常常做发生失速的梦，你知道最后掉到什么地方去了吗？
<br>细小的，像在明晃晃的光线里飞舞的灰尘一样淡而静的旖旎，将放浪形骸一笔瓦解勾销，化作烟尘，一并漂浮在柔和的明亮里。
<br>有天一早D去上班前，照例到房间里来拿干净衬衫，这回我没有睁眼打招呼，我感到他在边上坐了一会儿，然后听到“嗒”的一声，是我记事本上扣子的声音。我一下子全醒了，依然闭着眼没动。过去数年，这人还是碰见了他熟悉的我曾惯用的那种有日程栏和带扣子的记事本又忍不住打开。这是两年前写着的本子，我只为要抄着的电话号码带着，里头只有些跟今日与往昔都扯不上一点儿干系的闲杂小事，抄着两首诗，一段灯光笔记，只有一笔轻描淡写说到D要求我做件事，我一如既往好说话，一口答应。他出门前我让他知道我醒了，对他笑笑，他笑笑说你睡吧。
<br>最后一天我独自在家也忍不住打开那些从来没动过念头要碰一碰的抽屉，看了许多照片，还有他只写了三四天三四页的日记。用了他的香水听了他的唱片看了一张影碟，他说“喜欢什么就拿去”，我想起一个童话里国王打发曾身披渔网觐见他的王后时也说这话，我顺走了茶几下扔着的一个小望远镜，锁上门，把钥匙扔进报箱。
<br>
<br>而今四周围又全是雪了，随着火车奔驰，天越来越亮不清楚，上午八点多日出了，丝丝的红从裂口渗出来，遇到雪地上的蓝色纠缠成一种绵软蒙昧的淡紫，往后的数个小时里天地间全是昏昏欲睡的微明，接着是一阵下午的暴风卷走所有停泊在苍茫林海上的雪，什么也看不见，风雪过去以后树木都变成黑色，天空也变成黑色，雪地湛蓝，星斗满天。
<br>我断断续续睡个不停。
<br>
<br>火车在一头栽进北冰洋之前及时停下，走出车站便看到积雪峡谷及其中的科拉湾的港口。北大西洋暖流使它经年不冻。
<br>城北一片丘陵，从绿色岬角可以望见倾俯向港湾的城市面貌。我来时是清早，天不明不白亮了，深浅不一的蓝色莹莹落下，对面一片苍山茫雪。岬角上矗立着四十米高的战士铜像，叫阿廖沙。后来刮起了风，高处的风来得很猛，我有被卷落的危险，不得不先退避一下。狂风的呼号给我留下了深刻的印象。阿廖沙就永远这么独个儿站着，眺望远方，令人难忘。
<br>“请问航母去印度了吗？”在夜晚的小吃店，我试着这么问一个人。他没听清，可能我的口音不对，问题又突兀，他让我再说一遍。我笑笑不好意思再问，扯到了别的话题，“今夜太暖，看不到极光了。”“没错。”他点点头。我把航母同我喜欢的鲸、象或北极熊（虽然北极熊的体格相比其它的熊要小一些）一类的大家伙归在一起，未必准确的印象里，装备“玄武岩”的巴库号在摩尔曼斯克军港久久沉疴不起，飞机像鸟一样在上头起落盘旋，月明星稀，绕树三匝。绝大多数情况下我对这些东西都抱着天真的感情用事的想法，出于这样的想法，想知道这庞然大物是否连送带卖改头换面地远赴印度洋，还是仍是留在这附近的难以割舍的一堆废铁。
<br>这是一个风气正派简朴、给人好感的小城，丝毫没有浮夸或萎靡的踪影，街上常有深蓝色海军制服的年轻人，商店不多，人们神情平和愉快，裹着迷彩厚棉衣的士兵在空旷的雪地上滑雪，后来我又在博物馆遇上他们。博物馆小而内容全面。底楼还有当地木偶剧团三百年庆，花十卢布门票时抱着无所谓的态度，但发现木偶们朴素地不卑不亢地待着，即使忧伤也无自怜，快乐不是时髦的情绪，它们一点儿不时髦，两个演员高高兴兴地端着他们活动起来，这些我都喜欢。城里的几个餐厅体面明快，我在那儿吃了庆祝自己生日的午餐。渡口有船开往对岸，每班间隔时间挺长，深夜的这会儿空寂无人，远远近近停着的船叫人安心又舒服。晚上人们穿戴整齐上剧院去看一个叫《月光》的小爱情喜剧，布置和剧情都非常简单，我忽然就想起了以往在学校里的日子，大伙儿笑得快活，没比这再好的了。坐车二十分钟能到城市边缘，有大桥和正在建的新桥，桥那边是别的城市。
<br>
<br>回莫斯科，三儿说决定去彼得堡啦，他女朋友一俄国姑娘略加思索立马说：“好啊，我可以在那儿找份工作。”他有点头疼，我们拿他打趣，不过没什么，什么都会好的，什么都不是问题。
<br>再见到巴沙，还是美，也过生日，我们一般年纪，一伙人少不了喝酒。回去的路上从结冰的坡上滑下去玩了两三遭。三儿走啊走啊，脚底下一滑，跌到积雪的沟里去了，喝高了，也没出声，我们一直走到拐弯才发觉，回去找他把他拖出来。', '不足一个月的寒假之后回到莫斯科，仍白雪皑皑，夜空湛蓝冷艳，换心底一声叹息，当下无话。第二天便搭乘火车去往摩尔曼斯克。从天气预报看当地气温竟也不过零下五度左右，已经知道极光是看不到的了，除非气温一夜陡降十几二十度，可能性微乎其微。这趟旅行但出于某种需要，类似高烧睡梦中的一句呻吟，或在泳池中的想法：“游到那头再游回来”，其实停着不动未尝不可。

